import anthropic

client = anthropic.Anthropic()


def beam_search(
    problem: str,
    branching: int = 3,
    beam_width: int = 2,
    max_depth: int = 3,
) -> list[str]:
    """BFS beam search: at each depth keep only the top `beam_width` paths."""

    # Each beam entry is (path_as_list, cumulative_score)
    beam: list[tuple[list[str], float]] = [([],  0.0)]

    for depth in range(max_depth):
        candidates: list[tuple[list[str], float]] = []

        for path, cum_score in beam:
            context = " → ".join(path) if path else "(start)"
            resp = client.messages.create(
                model="claude-haiku-4-5-20251001",
                max_tokens=300,
                temperature=0.7,
                messages=[{
                    "role": "user",
                    "content": (
                        f"Problem: {problem}\n"
                        f"Path: {context}\n"
                        f"List {branching} candidate next steps, numbered."
                    ),
                }],
            ).content[0].text.strip()

            thoughts = [
                l.strip().lstrip("0123456789.-) ")
                for l in resp.splitlines() if l.strip()
            ][:branching]

            for t in thoughts:
                score_resp = client.messages.create(
                    model="claude-haiku-4-5-20251001",
                    max_tokens=10,
                    temperature=0.0,
                    messages=[{
                        "role": "user",
                        "content": (
                            f"Problem: {problem}\nPath: {context} → {t}\n"
                            "Score 0–10. Reply with the number only."
                        ),
                    }],
                ).content[0].text.strip()
                try:
                    score = float(score_resp.split()[0])
                except (ValueError, IndexError):
                    score = 5.0
                candidates.append((path + [t], cum_score + score))

        # Keep top beam_width by cumulative score
        beam = sorted(candidates, key=lambda x: x[1], reverse=True)[:beam_width]
        print(f"Depth {depth+1}: top beam score = {beam[0][1]:.1f}")

    return beam[0][0]  # return the highest-scored complete path


problem = "Describe a 3-step approach to debugging a memory leak in a Python application."
path = beam_search(problem, branching=3, beam_width=2, max_depth=3)
print("\nSelected path:")
for i, step in enumerate(path, 1):
    print(f"  {i}. {step}")
